import warnings
from enum import Enum
from typing import Optional, List, Tuple, Union

from pydantic import BaseModel, Field, ConfigDict, model_validator, field_validator

from floogen.utils import (
    cdiv,
    sv_param_decl,
    sv_typedef,
    sv_struct_typedef,
    bool_to_sv,
    snake_to_camel,
    sv_struct_render
)


class RouteAlgo(Enum):
    """Routing algorithm enum."""

    XY = "XYRouting"
    YX = "YXRouting"
    ID = "IdTable"
    SRC = "SourceRouting"

    def __str__(self):
        return f"{self.name}"


class WideRwDecouple(Enum):
    """Read/write decoupling mode for the wide link (mirrors wide_rw_decouple_e in floo_pkg).

    NONE  — shared wide link, no decoupling (default)
    VC    — decouple using virtual channels (requires vc_impl)
    PHYS  — decouple using separate physical wide links
    """

    NONE = "None"
    VC = "Vc"
    PHYS = "Phys"

    def __str__(self):
        return self.value


class VcImpl(Enum):
    """Virtual channel implementation enum (mirrors vc_impl_e in floo_pkg).

    Only relevant when ``decouple_rw == WideRwDecouple.VC``.
    """

    NAIVE = "VcNaive"
    CREDIT = "VcCredit"
    PREEMPT = "VcPreemptValid"

    def __str__(self):
        return self.value


class NarrowReductionOp(Enum):
    """Integer ALU reduction operations available on the narrow router."""
    Add = "Add"
    Mul = "Mul"
    MinS = "MinS"
    MinU = "MinU"
    MaxS = "MaxS"
    MaxU = "MaxU"


class WideReductionOp(Enum):
    """Floating-point reduction operations available on the wide router."""
    Add = "Add"
    Mul = "Mul"
    Min = "Min"
    Max = "Max"


class ReductionCfg(BaseModel):
    """Base reduction hardware configuration shared by narrow and wide channels."""
    model_config = ConfigDict(extra="forbid")

    rd_pipeline_depth: int = 0
    cut_offload_intf:  bool = False

    @model_validator(mode="before")
    @classmethod
    def _coerce_input(cls, v):
        """Coerce bool / list → dict so Pydantic can build the model normally."""
        if v is True:
            return {}
        if isinstance(v, list):
            return {"ops": v}
        return v

    def render_cfg(self) -> dict:
        """Return a dict representing ``reduction_cfg_t`` for sv_struct_render."""
        return {
            "RdPipelineDepth": self.rd_pipeline_depth,
            "CutOffloadIntf":  bool_to_sv(self.cut_offload_intf),
        }


class NarrowReductionCfg(ReductionCfg):
    """Reduction configuration for the narrow link."""
    ops: List[NarrowReductionOp] = Field(
        default_factory=lambda: list(NarrowReductionOp)
    )

    @field_validator("ops", mode="before")
    @classmethod
    def _parse_ops(cls, v):
        if isinstance(v, list):
            return [NarrowReductionOp[x] if isinstance(x, str) else x for x in v]
        return v


class WideReductionCfg(ReductionCfg):
    """Reduction configuration for the wide link."""
    ops: List[WideReductionOp] = Field(
        default_factory=lambda: list(WideReductionOp)
    )

    @field_validator("ops", mode="before")
    @classmethod
    def _parse_ops(cls, v):
        if isinstance(v, list):
            return [WideReductionOp[x] if isinstance(x, str) else x for x in v]
        return v


class CollectiveCfg(BaseModel):
    """User-facing collective operation configuration.

    The five high-level knobs map to ``collective_cfg_t`` in floo_pkg:

    +-----------------------+--------------------------------------------+
    | YAML field            | floo_pkg bits set                          |
    +=======================+============================================+
    | en_narrow_multicast   | OpCfg.EnNarrowMulticast                    |
    | en_wide_multicast     | OpCfg.EnWideMulticast                      |
    | en_barrier            | OpCfg.EnLSBAnd                             |
    | en_narrow_reduction   | OpCfg.EnA_{Add,Mul,MinS,MinU,MaxS,MaxU}   |
    | en_wide_reduction     | OpCfg.EnF_{Add,Mul,Min,Max}                |
    +-----------------------+--------------------------------------------+

    For ``en_narrow_reduction`` / ``en_wide_reduction``:
      - ``false`` / omitted   → disabled (default)
      - ``true``              → all ops enabled, default hw config
      - ``[Add, Mul, ...]``   → only the listed ops, default hw config
      - ``{ops: [...], rd_pipeline_depth: N, cut_offload_intf: true}``
                              → full per-channel control
    """

    model_config = ConfigDict(extra="forbid")

    en_narrow_multicast: bool = False
    en_wide_multicast:   bool = False
    en_barrier:          bool = False
    en_narrow_reduction: Optional[NarrowReductionCfg] = None
    en_wide_reduction:   Optional[WideReductionCfg] = None

    @field_validator("en_narrow_reduction", "en_wide_reduction", mode="before")
    @classmethod
    def _parse_reduction(cls, v):
        """Map false/null → None; everything else is handled by ReductionCfg's model_validator."""
        if v is None or v is False:
            return None
        return v

    def _narrow_ops(self) -> List[NarrowReductionOp]:
        if self.en_narrow_reduction is None:
            return []
        return self.en_narrow_reduction.ops

    def _wide_ops(self) -> List[WideReductionOp]:
        if self.en_wide_reduction is None:
            return []
        return self.en_wide_reduction.ops

    @property
    def en_multicast(self) -> bool:
        return self.en_narrow_multicast or self.en_wide_multicast

    @property
    def en_reduction(self) -> bool:
        return self.en_narrow_reduction is not None or self.en_wide_reduction is not None

    @property
    def en_collective(self) -> bool:
        """True when any collective feature is enabled (multicast, barrier, or reduction)."""
        return self.en_multicast or self.en_reduction or self.en_barrier

    def render_op_cfg(self) -> dict:
        """Return a dict representing ``collect_op_fe_cfg_t`` for sv_struct_render."""
        narrow = self._narrow_ops()
        wide = self._wide_ops()
        return {
            "EnNarrowMulticast": bool_to_sv(self.en_narrow_multicast),
            "EnWideMulticast":   bool_to_sv(self.en_wide_multicast),
            "EnLSBAnd":          bool_to_sv(self.en_barrier),
            "EnF_Add":           bool_to_sv(WideReductionOp.Add in wide),
            "EnF_Mul":           bool_to_sv(WideReductionOp.Mul in wide),
            "EnF_Min":           bool_to_sv(WideReductionOp.Min in wide),
            "EnF_Max":           bool_to_sv(WideReductionOp.Max in wide),
            "EnA_Add":           bool_to_sv(NarrowReductionOp.Add in narrow),
            "EnA_Mul":           bool_to_sv(NarrowReductionOp.Mul in narrow),
            "EnA_Min_S":         bool_to_sv(NarrowReductionOp.MinS in narrow),
            "EnA_Min_U":         bool_to_sv(NarrowReductionOp.MinU in narrow),
            "EnA_Max_S":         bool_to_sv(NarrowReductionOp.MaxS in narrow),
            "EnA_Max_U":         bool_to_sv(NarrowReductionOp.MaxU in narrow),
        }

    def render(self) -> dict:
        """Return a dict representing ``collective_cfg_t`` for sv_struct_render."""
        return {
            "OpCfg":  self.render_op_cfg(),
            "RedCfg": {"RdPipelineDepth": 0, "CutOffloadIntf": "1'b0"},
        }

    def render_narrow_reduction_cfg(self) -> str:
        """Render ``NarrowReductionCfg`` localparam; empty when reduction is disabled."""
        if self.en_narrow_reduction is None:
            return ""
        return sv_param_decl(
            "NarrowReductionCfg",
            sv_struct_render(self.en_narrow_reduction.render_cfg()),
            dtype="reduction_cfg_t",
        )

    def render_wide_reduction_cfg(self) -> str:
        """Render ``WideReductionCfg`` localparam; empty when reduction is disabled."""
        if self.en_wide_reduction is None:
            return ""
        return sv_param_decl(
            "WideReductionCfg",
            sv_struct_render(self.en_wide_reduction.render_cfg()),
            dtype="reduction_cfg_t",
        )


class XYDirections(Enum):
    """XY directions enum."""

    NORTH = 0
    EAST = 1
    SOUTH = 2
    WEST = 3
    EJECT = 4

    @classmethod
    def reverse(cls, direction: int):
        """Reverse the direction."""
        return (direction + 2) % 4 if direction != 4 else 4

    @classmethod
    def to_coords(cls, direction: int):
        """Convert the direction to coordinates."""
        return {
            cls.NORTH.value: Coord(x=0, y=1),
            cls.EAST.value: Coord(x=1, y=0),
            cls.SOUTH.value: Coord(x=0, y=-1),
            cls.WEST.value: Coord(x=-1, y=0),
            cls.EJECT.value: Coord(x=0, y=0),
        }[direction]

    def __str__(self):
        return self.name

    def __int__(self):
        return self.value

class SimpleId(BaseModel):
    """ID class."""

    id: int

    def __hash__(self):
        return hash(self.id)

    def __add__(self, other):
        """Add the ID."""
        return self.id + other.id

    def __sub__(self, other):
        """Subtract the ID."""
        return self.id - other.id

    def __lt__(self, other):
        """Less than comparison."""
        return self.id < other.id

    @field_validator("id")
    @classmethod
    def validate_id(cls, v):
        """Validate the ID."""
        if v < 0:
            raise ValueError("ID must be positive")
        return v

    def render(self, as_index=False):
        """Render the SystemVerilog ID."""
        if not as_index:
            return f"{self.id}"
        return f"[{self.id}]"


class Coord(BaseModel):
    """2D coordinate class."""

    x: int
    y: int
    port_id: int = 0

    def __hash__(self):
        return hash((self.x, self.y, self.port_id))

    def __add__(self, other):
        return Coord(x=self.x + other.x, y=self.y + other.y, port_id=self.port_id + other.port_id)

    def __sub__(self, other):
        return Coord(x=self.x - other.x, y=self.y - other.y, port_id=self.port_id - other.port_id)

    def __lt__(self, other):
        if self.y < other.y:
            return True
        if self.y == other.y:
            return self.x < other.x
        if self.x == other.x:
            return self.port_id < other.port_id
        return False

    @staticmethod
    def from_dict(coord_dict: dict):
        """Create a Coord object from a dictionary."""
        if isinstance(coord_dict, dict):
            return Coord(
                x=coord_dict.get("x", 0),
                y=coord_dict.get("y", 0),
                port_id=coord_dict.get("port_id", 0)
            )
        return None

    def render(self, as_index=False):
        """Render the SystemVerilog coordinate."""
        if not as_index:
            return f"'{{x: {self.x}, y: {self.y}, port_id: {self.port_id}}}"
        return f"[{self.x}][{self.y}]"

    @staticmethod
    def get_dir(node, neighbor) -> XYDirections:
        """Get the direction from node to neighbor."""
        if node.x == neighbor.x and node.y == neighbor.y:
            return XYDirections.EJECT
        if node.x == neighbor.x:
            if node.y > neighbor.y:
                return XYDirections.SOUTH
            return XYDirections.NORTH
        if node.y == neighbor.y:
            if node.x > neighbor.x:
                return XYDirections.WEST
            return XYDirections.EAST
        raise ValueError("Invalid neighbor")


class AddrRange(BaseModel):
    """Address range class."""

    model_config = ConfigDict(extra="forbid", validate_assignement=True)

    start: int = Field(ge=0)
    end: int = Field(ge=0)
    size: int
    base: Optional[int] = None
    arr_idx: Optional[Tuple[int, ...]] = None
    arr_dim: Optional[Tuple[int, ...]] = None
    rdl_name: Optional[str] = None
    en_multicast: bool = False
    desc: Optional[str] = None

    def __str__(self):
        return f"[{self.start:X}:{self.end:X}]"

    @model_validator(mode="before")
    def validate_input(self):
        """Validate the address range."""
        if not isinstance(self, dict):
            raise ValueError("Invalid address range specification")
        addr_dict = {k: v for k, v in self.items() if v is not None}
        match addr_dict:
            case {"size": size, "base": base, "arr_idx": arr_idx}:
                match arr_idx:
                    case (m,):
                        addr_dict["start"] = base + size * m
                        addr_dict["end"] = addr_dict["start"] + size
                    case (m, n):
                        if addr_dict["arr_dim"] is None:
                            raise ValueError("Array dimension must be specified for 2D arrays")
                        addr_dict["start"] = base + size * (m * addr_dict["arr_dim"][1] + n)
                        addr_dict["end"] = addr_dict["start"] + size
                    case _:
                        raise ValueError("Invalid array index specification")
            case {"size": size, "base": base}:
                addr_dict["start"] = base
                addr_dict["end"] = base + size
            case {"start": start, "end": end, "size": size}:
                if end - start != size:
                    raise ValueError("Invalid address range specification")
            case {"start": start, "end": end}:
                addr_dict["size"] = end - start
            case {"start": start, "size": size}:
                addr_dict["end"] = start + size
            case _:
                raise ValueError("Invalid address range specification")
        return addr_dict

    @model_validator(mode="after")
    def validate_output(self):
        """Validate the address range."""
        if self.start >= self.end:
            raise ValueError("Address range start must be less than end")
        return self

    def set_arr(self, arr_idx, arr_dim):
        """Update the address range with the given index."""
        self.arr_idx = arr_idx
        self.arr_dim = arr_dim
        if self.base is not None:
            match arr_idx:
                case (m,):
                    self.start = self.base + self.size * m
                case (m, n):
                    self.start = self.base + self.size * (m * arr_dim[1] + n)
            self.end = self.start + self.size
        else:
            raise ValueError("Address range base not set")
        return self


class RouteMapRule(BaseModel):
    """Routing rule class."""

    model_config = ConfigDict(arbitrary_types_allowed=True)

    dest: Union[SimpleId, Coord]
    addr_range: AddrRange
    desc: Optional[str] = None

    def __str__(self):
        return f"{self.addr_range} -> {self.dest}"

    def __lt__(self, other):
        return self.addr_range.start < other.addr_range.start

    def render(self, aw=None):
        """Render the SystemVerilog routing rule."""
        struct_fields = {
            "idx": self.dest.render(),
            "start_addr": self.addr_range.start,
            "end_addr": self.addr_range.end
        }
        if aw is not None:
            # Routing table use simple integers, and don't have any address width
            struct_fields["start_addr"] = f"{aw}'h{self.addr_range.start:0{cdiv(aw,4)}x}"
            struct_fields["end_addr"] = f"{aw}'h{self.addr_range.end:0{cdiv(aw,4)}x}"

        return sv_struct_render(struct_fields)

    def render_desc(self):
        '''Render the description of the routing rule.'''
        rule_desc = self.desc
        match self.addr_range.arr_idx:
            case (m,):
                rule_desc += f"_{m}"
            case (m, n):
                rule_desc += f"_x{m}_y{n}"
            case _:
                pass
        return rule_desc

    def get_rdl(self, instance_name, rdl_as_mem=False, rdl_memwidth=8):
        """Render the SystemRDL routing rule."""
        if self.addr_range.rdl_name is not None:
            return [
                {
                    "start_addr": self.addr_range.start,
                    "size": self.addr_range.size,
                    "rdl_name": self.addr_range.rdl_name,
                    "instance_name": instance_name,
                    "arr_dim": self.addr_range.arr_dim,
                }
            ]
        if rdl_as_mem:
            mementries = (self.addr_range.end - self.addr_range.start) // rdl_memwidth * 8
            mem_string = (
                f"external mem {{ mementries = 0x{mementries:X}; memwidth = {rdl_memwidth}; }}"
            )
            return [
                {
                    "start_addr": self.addr_range.start,
                    "size": self.addr_range.size,
                    "rdl_name": mem_string,
                    "instance_name": instance_name,
                    "arr_dim": self.addr_range.arr_dim,
                }
            ]
        return []

class RouteMapRuleMcast(RouteMapRule):
    """Routing rule class for multicast information."""

    mask_offset: Optional[Tuple[int, int]] = None
    mask_len: Optional[Tuple[int, int]] = None
    base_id: Optional[Tuple[int, int]] = None

    def render(self, aw=None):
        """Render the SystemVerilog routing rule."""
        if aw is None:
            raise ValueError("Address width must be specified for multicast routing")

        # In multicast, the `idx` field becomes a nested structure
        # where the `id` is the original `idx`
        struct_fields = {
            "idx": {"id": self.dest.render()},
            "start_addr": f"{aw}'h{self.addr_range.start:0{cdiv(aw,4)}x}",
            "end_addr": f"{aw}'h{self.addr_range.end:0{cdiv(aw,4)}x}",
        }

        # Non-multicast nodes, don't need any mask information
        if self.mask_offset is None:
            struct_fields["idx"]["mask_x"] = {"default": "'0"}
            struct_fields["idx"]["mask_y"] = {"default": "'0"}
        else:
            struct_fields["idx"]["mask_x"] = {"offset": self.mask_offset[0], "len": self.mask_len[0], "base_id": self.base_id[0]}
            struct_fields["idx"]["mask_y"] = {"offset": self.mask_offset[1], "len": self.mask_len[1], "base_id": self.base_id[1]}

        return sv_struct_render(struct_fields)


class RouteRule(BaseModel):
    """Routing rule class."""

    route: Optional[List[Tuple[int, int]]]
    id: Union[SimpleId, Coord]
    desc: Optional[str] = None

    def render(self, num_route_bits):
        """Render the SystemVerilog route."""
        route_str = ""
        route_bits_used = 0
        split_route = False
        if self.route is None:
            if split_route:
                return f"{num_route_bits}'d0"
            return f"{num_route_bits}'b{'0' * num_route_bits}"
        for port, num_bits in self.route:
            if split_route:
                route_str = f"{num_bits}'d{port}, " + route_str
            else:
                route_str = f"{port:0{num_bits}b}" + route_str
            route_bits_used += num_bits
        if route_bits_used > num_route_bits:
            raise ValueError("Not enough bits to encode the route")
        if route_bits_used < num_route_bits:
            if split_route:
                return f"{num_route_bits-route_bits_used}'d0, " + route_str[:-2]
            return f"{num_route_bits}'b{'0' * (num_route_bits-route_bits_used)}" + route_str
        if split_route:
            return route_str[:-2]
        return f"{num_route_bits}'b" + route_str


class RouteTable(BaseModel):
    """Route Table class, which can hold the route entries to each destination"""

    name: str
    routes: List[RouteRule]

    def __len__(self):
        return len(self.routes)

    @model_validator(mode="after")
    def sort_and_pad(self):
        """Sort by destination and fill in missing entries."""
        self.routes = sorted(self.routes, key=lambda x: x.id)
        for i, route in enumerate(self.routes):
            if i != route.id.id:
                self.routes.insert(i, RouteRule(route=None, id=SimpleId(id=i)))
        return self.routes.reverse()

    def render(self, num_route_bits, no_decl=False):
        """Render the SystemVerilog route table."""
        string = ""
        rules_str = ""
        if not self.routes:
            string += sv_param_decl(
                f"{snake_to_camel(self.name)}",
                value="'{default: 0}",
                dtype="route_t",
            )
            return string
        string += sv_param_decl(f"{snake_to_camel(self.name)}NumRoutes", len(self.routes)) + "\n"
        for i, rule in enumerate(self.routes):
            rules_str += f"{rule.render(num_route_bits)}"
            rules_str += "," if i != len(self.routes) - 1 else " "
            if rule.desc is not None:
                rules_str += f"// {rule.desc}"
            rules_str += "\n"
        if no_decl:
            return "'{\n" + rules_str + "}"
        string += sv_param_decl(
            f"{snake_to_camel(self.name)}",
            value="'{\n" + rules_str + "\n}",
            dtype="route_t",
            array_size=f"{snake_to_camel(self.name)}NumRoutes-1",
        )
        return string


class RouteMap(BaseModel):
    """Route Map class, which can represent the system address map (SAM),
    or a routing table of a router."""

    name: str
    rules: List[RouteMapRule]

    def __str__(self):
        return f"{self.rules}"

    def __len__(self):
        return len(self.rules)

    def rule_type(self):
        """Return the type of the rules."""
        return self.name + "_rule_t"

    @model_validator(mode="after")
    def check_no_overlapping_ranges(self):
        """Check if there are no overlapping ranges."""
        rules = sorted(self.rules)
        for i in range(len(rules) - 1):
            if rules[i].addr_range.end > rules[i + 1].addr_range.start:
                raise ValueError(
                    f"Overlapping ranges: {rules[i].addr_range} and {rules[i+1].addr_range}\n \
                    {self.pprint()}"
                )
        return self

    def trim(self):
        """Optimize the routing table."""
        # Separate the rules by destination
        rules_by_dest = {}
        for rule in self.rules:
            rules_by_dest.setdefault(rule.dest, []).append(rule)

        # Sort the rules by start address
        for dest, ranges in rules_by_dest.items():
            rules_by_dest[dest] = sorted(ranges)

        # Merge the rules if the end of one range is the start of the next
        for dest, ranges in rules_by_dest.items():
            i = 0
            while i < len(ranges) - 1:
                if ranges[i].addr_range.end == ranges[i + 1].addr_range.start:
                    ranges[i].addr_range.end = ranges[i + 1].addr_range.end
                    ranges[i].addr_range.size = (
                        ranges[i].addr_range.end - ranges[i].addr_range.start
                    )
                    del ranges[i + 1]
                else:
                    i += 1

        # Combine the rules into a single table again
        self.rules = []
        for dest, ranges in rules_by_dest.items():
            for rule in ranges:
                self.rules.append(rule)

        # Validate the routing table
        self.model_validate(self)

    def render(self, aw=None):
        """Render the SystemVerilog routing table."""
        string = ""
        rules = self.rules.copy()
        # typedef of the address rule
        string += sv_param_decl(f"{snake_to_camel(self.name)}NumRules", len(rules)) + "\n"
        addr_type = f"logic [{aw-1}:0]" if aw is not None else "id_t"
        rule_type_dict = {}
        if not isinstance(rules[0], RouteMapRuleMcast):
            rule_type_dict = {"idx": "id_t", "start_addr": addr_type, "end_addr": addr_type}
            string += sv_struct_typedef(self.rule_type(), rule_type_dict)
        else:
            rule_type_dict = {"offset": "int unsigned", "len": "int unsigned", "base_id": "int unsigned"}
            string += sv_struct_typedef("mcast_mask_sel_t", rule_type_dict)
            rule_type_dict = {"id": "id_t", "mask_x": "mcast_mask_sel_t", "mask_y": "mcast_mask_sel_t"}
            string += sv_struct_typedef("mcast_idx_t", rule_type_dict)
            rule_type_dict = {"idx": "mcast_idx_t", "start_addr": addr_type, "end_addr": addr_type}
            string += sv_struct_typedef(self.rule_type(), rule_type_dict)

        rules_str = ""
        if not rules:
            string += sv_param_decl(
                f"{snake_to_camel(self.name)}",
                value="'{default: 0}",
                dtype=self.rule_type(),
            )
            return string
        for i, rule in enumerate(rules):
            rules_str += f"{rule.render(aw)}"
            rules_str += ',' if i != len(rules) - 1 else ' '
            if rule.desc is not None:
                rules_str += f"// {snake_to_camel(rule.render_desc())}\n"
        string += sv_param_decl(
            f"{snake_to_camel(self.name)}",
            value="'{\n" + rules_str + "\n}",
            dtype=self.rule_type(),
            array_size=f"{snake_to_camel(self.name)}NumRules-1"
        )
        return string

    def render_rdl(self, rdl_as_mem=False, rdl_memwidth=8):
        """Render the SystemRDL addrmap internals."""
        string = ""
        rules = self.rules.copy()
        rdl_setups = []
        for i, rule in enumerate(rules):
            match rule.addr_range.arr_idx:
                case None:
                    pass
                case (m,) if m != 0:
                    continue
                case (m, n) if m != 0 or n != 0:
                    continue
            block_name = f"{self.name}_{i}"
            if rule.desc is not None:
                block_name = rule.desc
            rdl_setups.extend(rule.get_rdl(f"{block_name}", rdl_as_mem, rdl_memwidth))
        newlist = sorted(rdl_setups, key=lambda d: d['start_addr'])
        for item in newlist:
            string += f"  {item['rdl_name']} {item['instance_name']}"
            match item['arr_dim']:
                case (m,):
                    string += f"[{m}]"
                case (m, n):
                    string += f"[{m*n}]"
                case _:
                    pass
            string += f" @0x{item['start_addr']:X}"
            if item['arr_dim'] is not None:
                string += f" += 0x{item['size']:X}"
            string += ";\n"
        return string

    def render_rdl_inc(self):
        """Render the SystemRDL include header."""
        string = ""
        rules = self.rules.copy()
        rdl_names = []
        for rule in rules:
            if rule.addr_range.rdl_name is not None:
                rdl_names.append(rule.addr_range.rdl_name.split()[0].split('#')[0])
        # uniquify the names
        rdl_names = sorted(list(set(rdl_names)))
        for rule in rdl_names:
            string += f"`include \"{rule}.rdl\"\n"
        return string

    def pprint(self):
        """Pretty print the routing table."""
        for rule in self.rules:
            print(rule)


class Routing(BaseModel):
    """
    The class that holds essentially all the routing information needed.

    Attributes:
        route_algo (RouteAlgo): The routing algorithm to use. See RouteAlgo enum for the options.
        use_id_table (bool): Whether to use a table to decode the destination ID.
        sam (RouteMap): The system address map.
        table (RouteMap): The routing table of the router.
        addr_offset_bits (int): The number of bits to decode the X and Y coordinates from the address. Only used if `use_id_table` is False and `route_algo` is XY.
        xy_id_offset (Union[SimpleId, Coord]): A constant offset to add to the X and Y coordinates. Only used if `route_algo` is XY.
        num_endpoints (int): The number of endpoints in the network.
        num_id_bits (int): The number of bits to represent the ID. Only used if `route_algo` is ID or SRC.
        num_x_bits (int): The number of bits to represent the X coordinate. Only used if `route_algo` is XY.
        num_y_bits (int): The number of bits to represent the Y coordinate. Only used if `route_algo` is XY.
        num_route_bits (int): The number of bits to represent the route. Only used if `route_algo` is SRC.
        addr_width (int): The width of the address bus.
        rob_idx_bits (int): The number of bits to represent the reorder buffer index.
        port_id_bits (int): The number of bits to represent the local port ID.
        en_multicast (bool): Whether to enable multicast support. Only supported with XY routing.
        multicast_sam (RouteMap): The multicast system address map. Only used if `en_multicast` is True.
        en_parallel_reduction (bool): Whether to enable parallel reduction support (Experimental)
        en_narrow_offload_reduction (bool): Whether to enable narrow offload reduction support (Experimental)
        en_wide_offload_reduction (bool): Whether to enable wide offload reduction support
    """

    model_config = ConfigDict(arbitrary_types_allowed=True, extra="forbid")

    route_algo: RouteAlgo
    use_id_table: bool = True
    sam: Optional[RouteMap] = None
    table: Optional[RouteMap] = None
    addr_offset_bits: Optional[int] = None
    xy_id_offset: Optional[Union[SimpleId, Coord]] = None
    num_endpoints: Optional[int] = None
    num_id_bits: Optional[int] = None
    num_x_bits: Optional[int] = None
    num_y_bits: Optional[int] = None
    num_route_bits: Optional[int] = None
    addr_width: Optional[int] = None
    rob_idx_bits: int = 1
    port_id_bits: int = 1
    num_vc_id_bits: int = 0
    decouple_rw: WideRwDecouple = WideRwDecouple.NONE
    vc_impl: VcImpl = VcImpl.NAIVE
    multicast_sam: Optional[RouteMap] = None
    collective: CollectiveCfg = CollectiveCfg()

    @property
    def en_multicast(self) -> bool:
        """Convenience alias used by validators and hdr typedef rendering."""
        return self.collective.en_multicast

    @field_validator("route_algo", mode="before")
    @classmethod
    def validate_route_algo(cls, v):
        """Validate the routing algorithm."""
        if isinstance(v, str):
            v = RouteAlgo[v]
        return v

    @field_validator("decouple_rw", mode="before")
    @classmethod
    def validate_decouple_rw(cls, v):
        """Accept bool (False→NONE) or string/enum name."""
        if isinstance(v, bool):
            return WideRwDecouple.NONE if not v else WideRwDecouple.PHYS
        if isinstance(v, str):
            return WideRwDecouple[v.upper()]
        return v

    @field_validator("vc_impl", mode="before")
    @classmethod
    def validate_vc_impl(cls, v):
        """Accept both enum members and string names."""
        if isinstance(v, str):
            v = VcImpl[v.upper()]
        return v

    @model_validator(mode="after")
    def validate_vc_cfg(self):
        """Warn if vc_impl is set but decouple_rw is not Vc."""
        if self.decouple_rw != WideRwDecouple.VC and self.vc_impl != VcImpl.NAIVE:
            warnings.warn(
                f"vc_impl={self.vc_impl} has no effect unless decouple_rw is set to 'Vc'",
                UserWarning,
                stacklevel=2,
            )
        return self

    @model_validator(mode="after")
    def validate_multicast_route_algo(self):
        """Multicast is supported with XY routing only"""
        if self.en_multicast and self.route_algo != RouteAlgo.XY:
            raise ValueError(
                "Multicast is only supported with XY routing algorithm, "
                f"but got {self.route_algo}"
            )
        return self
    def render_param_decl(self) -> str:
        """Render the SystemVerilog parameter declaration."""
        string = ""
        string += sv_param_decl("RouteAlgo", self.route_algo.value, dtype="route_algo_e")
        string += sv_param_decl("UseIdTable", bool_to_sv(self.use_id_table), dtype="bit")
        match (self.route_algo):
            case RouteAlgo.XY:
                string += sv_param_decl("NumXBits", self.num_x_bits)
                string += sv_param_decl("NumYBits", self.num_y_bits)
            case RouteAlgo.ID:
                string += sv_param_decl("NumIdBits", self.num_id_bits)
            case _:
                pass

        if self.route_algo == RouteAlgo.XY:
            string += sv_param_decl("XYAddrOffsetX", self.addr_offset_bits)
            string += sv_param_decl("XYAddrOffsetY", self.addr_offset_bits + self.num_x_bits)
        else:
            string += sv_param_decl("XYAddrOffsetX", 0)
            string += sv_param_decl("XYAddrOffsetY", 0)
        if self.route_algo == RouteAlgo.ID and not self.use_id_table:
            string += sv_param_decl("IdAddrOffset", self.addr_offset_bits)
        else:
            string += sv_param_decl("IdAddrOffset", 0)
        return string

    def render_typedefs(self) -> str:
        """Render the SystemVerilog typedefs."""
        string = ""
        string += sv_typedef("rob_idx_t", array_size=self.rob_idx_bits)
        if self.port_id_bits > 0:
            string += sv_typedef("port_id_t", array_size=self.port_id_bits)
        match self.route_algo:
            case RouteAlgo.XY:
                string += sv_typedef("x_bits_t", array_size=self.num_x_bits)
                string += sv_typedef("y_bits_t", array_size=self.num_y_bits)
                id_fields = {"x": "x_bits_t", "y": "y_bits_t"}
                if self.port_id_bits > 0:
                    id_fields["port_id"] = "port_id_t"
                string += sv_struct_typedef("id_t", id_fields)
                string += sv_typedef("route_t", "logic")
            case RouteAlgo.ID:
                string += sv_typedef("id_t", array_size=self.num_id_bits)
                string += sv_typedef("route_t", "logic")
            case RouteAlgo.SRC:
                string += sv_typedef("id_t", array_size=self.num_id_bits)
                string += sv_typedef("route_t", array_size=self.num_route_bits)
            case _:
                pass
        if self.num_vc_id_bits > 0:
            string += sv_typedef("vc_id_t", array_size=self.num_vc_id_bits)
        return string

    def render_hdr_typedef(self, network_type) -> str:
        """Render the SystemVerilog flit header."""

        dst_type = "route_t" if self.route_algo == RouteAlgo.SRC else "id_t"
        ch_type = "axi_ch_e" if network_type == "axi" else "nw_ch_e"

        if self.num_vc_id_bits == 0:
            if self.collective.en_collective:
                return (
                    f"`FLOO_TYPEDEF_HDR_T(hdr_t, {dst_type}, id_t, {ch_type}, rob_idx_t,"
                    f" id_t, collect_op_t)")
            return f"`FLOO_TYPEDEF_HDR_T(hdr_t, {dst_type}, id_t, {ch_type}, rob_idx_t)"
        return f"`FLOO_TYPEDEF_VC_HDR_T(hdr_t, {dst_type}, id_t, {ch_type}, rob_idx_t, vc_id_t)"

    def render_route_cfg(self, name) -> str:
        """Render the SystemVerilog routing configuration."""
        fields = {
            "RouteAlgo": self.route_algo.value,
            "UseIdTable": bool_to_sv(self.use_id_table),
            "XYAddrOffsetX": self.addr_offset_bits if self.route_algo == RouteAlgo.XY else 0,
            "XYAddrOffsetY": self.addr_offset_bits + self.num_x_bits if
                                self.route_algo == RouteAlgo.XY else 0,
            "IdAddrOffset": self.addr_offset_bits if
                                self.route_algo == RouteAlgo.ID and not self.use_id_table else 0,
            "NumSamRules": len(self.sam),
            "NumRoutes": self.num_endpoints if self.route_algo == RouteAlgo.SRC else 0,
            "CollectiveCfg": self.collective.render(),
        }
        return sv_param_decl(name, sv_struct_render(fields), dtype="route_cfg_t")

    def render_vc_impl(self) -> str:
        """Render WideRwDecouple and (when Vc) VcImpl localparam declarations.
        Nothing is emitted when decouple_rw is None (the default)."""
        if self.decouple_rw == WideRwDecouple.NONE:
            return ""
        s = sv_param_decl("WideRwDecouple", str(self.decouple_rw), dtype="wide_rw_decouple_e") + "\n"
        if self.decouple_rw == WideRwDecouple.VC:
            s += sv_param_decl("VcImpl", str(self.vc_impl), dtype="vc_impl_e")
        return s

